#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long factorial(int n) {
    long long result = 1;
    for (int i = 2; i <= n; i++) {
        result = (result * i) % MOD;
    }
    return result;
}

long long modular_inverse(long long a) {
    long long result = 1;
    long long power = MOD - 2;
    while (power > 0) {
        if (power % 2 == 1) {
            result = (result * a) % MOD;
        }
        a = (a * a) % MOD;
        power /= 2;
    }
    return result;
}

int main() {
    int N;
    scanf("%d", &N);
    int* count = (int*) malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &count[i]);
    }
    int Q;
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int S;
        scanf("%d", &S);
        int* boxes = (int*) malloc(N * sizeof(int));
        for (int j = 0; j < N; j++) {
            boxes[j] = (count[j] + S - 1) / S;
        }
        long long total = factorial(N);
        for (int j = 0; j < N; j++) {
            total = (total * modular_inverse(factorial(boxes[j]))) % MOD;
        }
        printf("%lld\n", total);
        free(boxes);
    }
    free(count);
    return 0;
}

