code.Python3:
import sys
MOD = 1000000007
def factorial(n):
    result = 1
    for i in range(2, n + 1):
        result = (result * i) % MOD
    return result
def modular_inverse(a):
    result = 1
    power = MOD - 2
    while power > 0:
        if power % 2 == 1:
            result = (result * a) % MOD
        a = (a * a) % MOD
        power //= 2
    return result
def main():
    N = int(sys.stdin.readline())
    count = list(map(int, sys.stdin.readline().split()))
    Q = int(sys.stdin.readline())
    for _ in range(Q):
        S = int(sys.stdin.readline())
        boxes = [(c + S - 1) // S for c in count]
        total = factorial(sum(boxes))
        for b in boxes:
            total = (total * modular_inverse(factorial(b))) % MOD
        print(total)
if __name__ == '__main__':
    main()

